# Add validators to resolve relative overrides:
@validator('database_url', pre=True)
def resolve_database_url(cls, v):
    if v and not v.startswith('sqlite:///'):
        return v
    path = v.replace('sqlite:///', '')
    if Path(path).is_absolute():
        return v
    return f"sqlite:///{BACKEND_ROOT / path}"

@validator('storage_dir', pre=True)
def resolve_storage_dir(cls, v):
    if not v:
        return str(BACKEND_ROOT / "app" / "storage")
    p = Path(v)
    if p.is_absolute():
        return v
    return str(BACKEND_ROOT / v)

