# Add explicit bootstrap function:
def bootstrap_storage_tree(storage_dir: str | Path | None = None) -> None:
    base = Path(storage_dir) if storage_dir else BACKEND_ROOT / "app" / "storage"
    for subdir in ["raw", "artifacts", "datasets", "connectors",
                   "connector_reports", "connector_manifests",
                   "connector_snapshots", "connector_raw"]:
        (base / subdir).mkdir(parents=True, exist_ok=True)
